import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import socket from "../socket";

export default function JoinPage() {
  const [username, setUsername] = useState("");
  const [room, setRoom] = useState("");
  const [roomList, setRoomList] = useState([]);
  const [newRoom, setNewRoom] = useState("");
  const navigate = useNavigate();

  useEffect(() => {
    if (!socket.connected) socket.connect();

    socket.on("room-list", (data) => setRoomList(data));

    return () => socket.off("room-list");
  }, []);

  const handleJoin = () => {
    if (username && room) {
      navigate(`/chat?username=${username}&room=${room}`);
    }
  };

  const createRoom = () => {
    if (newRoom.trim()) {
      socket.emit("create-room", newRoom.trim());
      setNewRoom("");
    }
  };

  return (
    <div className="min-h-screen bg-yellow-400 flex items-center justify-center px-4">
      <div className="bg-white max-w-md w-full p-8 rounded-xl shadow-lg">
        <h1 className="text-3xl font-bold text-center text-gray-800 mb-2">
          Stay Connected, Anytime, Anywhere
        </h1>
        <p className="text-center text-sm text-gray-600 mb-6">
          Chat effortlessly with friends and family — no matter the distance.
        </p>

        <input
          type="text"
          placeholder="Enter your name"
          className="w-full p-3 mb-3 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-yellow-500"
          value={username}
          onChange={(e) => setUsername(e.target.value)}
        />

        <select
          className="w-full p-3 mb-3 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-yellow-500"
          value={room}
          onChange={(e) => setRoom(e.target.value)}
        >
          <option value="">Select a Room</option>
          {roomList.map((r) => (
            <option key={r} value={r}>
              {r}
            </option>
          ))}
        </select>

        <div className="flex gap-2 mb-4">
          <input
            type="text"
            placeholder="Create new room"
            className="flex-1 p-3 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-yellow-500"
            value={newRoom}
            onChange={(e) => setNewRoom(e.target.value)}
          />
          <button
            onClick={createRoom}
            className="bg-green-500 text-white px-4 rounded-md hover:bg-green-600"
          >
            +
          </button>
        </div>

        <button
          onClick={handleJoin}
          className="w-full bg-black text-white py-3 rounded-md font-semibold hover:bg-gray-900"
        >
          Get 50mins Free by Joining
        </button>
      </div>
    </div>
  );
}
